import React, { useState } from 'react';

export default function Auth() {
  // Separate states for signup form
  const [signupEmail, setSignupEmail] = useState('');
  const [signupPassword, setSignupPassword] = useState('');
  // Separate states for login form
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [message, setMessage] = useState('');

  async function handleSignup(e) {
    e.preventDefault();
    try {
      const response = await fetch('http://localhost:5000/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: signupEmail, password: signupPassword }),
      });
      const result = await response.json();
      if (!response.ok) {
        setMessage(result.error || 'Signup failed');
      } else {
        setMessage('Signup successful! Please log in.');
      }
    } catch (error) {
      setMessage('Error connecting to server during signup');
    }
  }

  async function handleLogin(e) {
    e.preventDefault();
    try {
      const res = await fetch('http://localhost:5000/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: loginEmail, password: loginPassword }),
      });
      const data = await res.json();
      if (!res.ok) {
        setMessage(data.error || 'Login failed');
      } else {
        setMessage('Login successful!');
        // You can add redirect or token storage here if needed
      }
    } catch (err) {
      setMessage('Error connecting to server during login');
    }
  }

  return (
    <div>
      <h2>Signup</h2>
      <form onSubmit={handleSignup}>
        <input
          type="email"
          placeholder="Email"
          value={signupEmail}
          onChange={e => setSignupEmail(e.target.value)}
          required
        />
        <input
          type="password"
          placeholder="Password"
          value={signupPassword}
          onChange={e => setSignupPassword(e.target.value)}
          required
        />
        <button type="submit">Sign Up</button>
      </form>

      <h2>Login</h2>
      <form onSubmit={handleLogin}>
        <input
          type="email"
          placeholder="Email"
          value={loginEmail}
          onChange={e => setLoginEmail(e.target.value)}
          required
        />
        <input
          type="password"
          placeholder="Password"
          value={loginPassword}
          onChange={e => setLoginPassword(e.target.value)}
          required
        />
        <button type="submit">Log In</button>
      </form>

      {message && <p>{message}</p>}
    </div>
  );
}
